{
  "ticket_id": "SCRUM-8",
  "plan_version": 1,
  "units": [
    {
      "id": "unit-1",
      "description": "Create auth library layer: password validation utility, bcrypt password hashing helpers, JSON-file-based user store (read/write/find by email), session store (create/validate/delete with 24h expiry), and IP-based rate limiter (5 attempts per minute). All pure server-side library code with no API route or UI dependencies.",
      "affected_files": [
        "src/lib/auth/validation.ts",
        "src/lib/auth/password.ts",
        "src/lib/auth/user-store.ts",
        "src/lib/auth/session-store.ts",
        "src/lib/auth/rate-limiter.ts",
        "src/lib/auth/types.ts",
        "src/__tests__/auth/validation.test.ts",
        "src/__tests__/auth/password.test.ts",
        "src/__tests__/auth/user-store.test.ts",
        "src/__tests__/auth/session-store.test.ts",
        "src/__tests__/auth/rate-limiter.test.ts",
        "data/.gitkeep"
      ],
      "dependencies": [],
      "complexity": "complex",
      "test_criteria": [
        {
          "scenario": "password_validation_rules",
          "test_type": "unit",
          "description": "Verify password validation rejects passwords under 8 chars, without uppercase, or without a number. Verify it accepts passwords meeting all requirements including boundary case of exactly 8 characters."
        },
        {
          "scenario": "rate_limit_login_attempts",
          "test_type": "unit",
          "description": "Verify rate limiter allows 5 attempts per IP per minute, returns blocked on 6th attempt, and resets after the window expires."
        },
        {
          "scenario": "session_expiry",
          "test_type": "unit",
          "description": "Verify session tokens created with crypto.randomUUID() are validated correctly, and sessions older than 24 hours are treated as expired."
        },
        {
          "scenario": "duplicate_email_detection",
          "test_type": "unit",
          "description": "Verify user store prevents creating a user with a duplicate email address."
        }
      ]
    },
    {
      "id": "unit-2",
      "description": "Create all four auth API route handlers: POST /api/auth/register (validate input, check duplicate email, hash password, store user, return success), POST /api/auth/login (validate credentials, check rate limit, verify password, create session, set httpOnly/Secure/SameSite cookie), GET /api/auth/me (read session cookie, validate session, return user or 401), POST /api/auth/logout (clear session, delete cookie, return success). All endpoints return consistent JSON error format with 'error' and 'message' fields.",
      "affected_files": [
        "src/app/api/auth/register/route.ts",
        "src/app/api/auth/login/route.ts",
        "src/app/api/auth/me/route.ts",
        "src/app/api/auth/logout/route.ts",
        "src/__tests__/auth/api-register.test.ts",
        "src/__tests__/auth/api-login.test.ts",
        "src/__tests__/auth/api-me.test.ts",
        "src/__tests__/auth/api-logout.test.ts"
      ],
      "dependencies": ["unit-1"],
      "complexity": "complex",
      "test_criteria": [
        {
          "scenario": "register_duplicate_email",
          "test_type": "integration",
          "description": "POST /api/auth/register with an already-registered email returns 409 with consistent error format."
        },
        {
          "scenario": "login_creates_session_cookie",
          "test_type": "integration",
          "description": "POST /api/auth/login with valid credentials returns 200 and sets an httpOnly cookie with a session token. Verify Secure and SameSite flags."
        },
        {
          "scenario": "auth_me_returns_user",
          "test_type": "integration",
          "description": "GET /api/auth/me with a valid session cookie returns the current user email. Without a cookie returns 401."
        },
        {
          "scenario": "rate_limit_login_attempts",
          "test_type": "integration",
          "description": "6th login attempt within 60 seconds from the same IP returns 429 with a retry-after header."
        },
        {
          "scenario": "logout_clears_session",
          "test_type": "integration",
          "description": "POST /api/auth/logout clears the session cookie, and a subsequent GET /api/auth/me returns 401."
        },
        {
          "scenario": "consistent_error_format",
          "test_type": "integration",
          "description": "All error responses from auth endpoints include 'error' and 'message' fields in the JSON body."
        }
      ]
    },
    {
      "id": "unit-3",
      "description": "Create the useAuth React hook and the NavigationHeader component. The useAuth hook calls GET /api/auth/me on mount, returns { user, loading, logout } where logout calls POST /api/auth/logout. The NavigationHeader component uses useAuth to show Login/Register links when logged out and Dashboard/Logout links when logged in
